INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (4, '14.', 'Kaliteyi belirlenen standartlara göre uyarlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (4, '15.', 'Yapılan işin kalitesini sürekli geliştirmek yönünde çalışır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (4, '16.', 'İş yapma yöntemine ilişkin akış ve prosedürlerdeki yeniliklere adapte olur.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (5, '17.', 'Çalışma ortamında iyi ilişkiler kurar ve korur.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (5, '18.', 'Takım arkadaşlarının yardıma ihtiyacı olduğunda gerekli destekte bulunur.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (5, '19.', 'Takım ruhuna uyumlu yaklaşımda bulunur.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (5, '20.', 'Takımdaki farklı görüşlere karşı toleranslıdır ve destekleyicidir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (6, '21.', 'İşlerin hatasız tamamlanması için çaba sarf eder.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (6, '22.', 'Küçük detaylara dikkat eder.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (6, '23.', 'İşin inceliklerini öğrenmek ve işin bütününe hâkim olabilmek için sürekli gözlem yapar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (6, '24.', 'Hataları, iş çıktıları paylaşılmadan fark eder.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (7, '25.', 'İş ortamında; kızgınlık, korku, kaygı, üzüntü, depresyon, vb. duygularını kontrol eder.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (7, '26.', 'Özel hayatında yaşadığı sıkıntıları, iş ortamına en az ölçüde yansıtır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (7, '27.', 'Zor çalışma koşullarında ve yoğun mesaide bile başarılı sonuçlar elde edebilir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (8, '28.', 'Mesleki motivasyonu yüksektir ve işini severek yapar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (8, '29.', 'Kendisine verilen işleri takip eder, doğru, eksiksiz ve zamanında sonuçlandırır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (8, '30.', 'Her zaman daha iyisini yapmak adına kendisini sürekli geliştirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (9, '1.', 'Dış görünüşüne, saçına, sakalına, kişisel hijyenine dikkat eder. Eldiven, bone kullanır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (9, '2.', 'Şirketin eğitimlerine aktif olarak katılır, atanmış eğitimlerini tamamlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (9, '3.', 'Restoran hedeflerinden haberdardır, hedef için elinden gelen gayreti gösterir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (9, '4.', 'Mazeret bildirmeden işe gelmemezlik yapmaz. Vardiya ve mola düzenine uyar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (10, '5.', 'Ürünleri reçetelere uygun hazırlar. Ürünlerin her seferinde aynı kalite ve tatta olmasını sağlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (10, '6.', 'Et pişirme tekniklerine hakimdir. Şirket standartlarına uygun pişirme yapar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (10, '7.', 'Patates kızartma standartlarını bilir, doğru şekilde uygular.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (10, '8.', 'Peynir çubukları, soğan halkası, nugget vb. ürünleri doğru sürede uygun sıcaklıkta pişirir.');

